async function getTodoRowByIdForUser(
  todoId: string,
  userId: string,
): Promise<TodoRow | null> {
  const result = await query<TodoRow>(
    `
      SELECT
        id,
        user_id,
        title,
        description,
        completed,
        status,
        last_status_transition_from,
        last_status_transition_at,
        due_date,
        priority,
        created_at,
        updated_at
      FROM todos
      WHERE id = $1
        AND user_id = $2
      LIMIT 1
    `,
    [todoId, userId],
  );

  return result.rows[0] ?? null;
}

export async function listTodosForUser(
  userId: string,
  options: ListTodosOptions = {},
): Promise<TodoRecord[]> {
  const values: unknown[] = [userId];
  const whereClauses = ["user_id = $1"];

  if (typeof options.completed === "boolean") {
    whereClauses.push(`completed = $${values.length + 1}`);
    values.push(options.completed);
  }

  if (typeof options.overdue === "boolean") {
    if (options.overdue) {
      whereClauses.push("completed = false");
      whereClauses.push("due_date IS NOT NULL");
      whereClauses.push("due_date < CURRENT_DATE");
    } else {
      whereClauses.push(
        "(completed = true OR due_date IS NULL OR due_date >= CURRENT_DATE)",
      );
    }
  }

  const sortField = options.sort ?? "createdAt";
  const sortOrder = options.order ?? "desc";
  const orderDirection = sortOrder.toUpperCase();
  const orderByClause =
    sortField === "priority"
      ? `
          CASE priority
            WHEN 'low' THEN 1
            WHEN 'medium' THEN 2
            WHEN 'high' THEN 3
          END ${orderDirection},
          created_at DESC,
          id DESC
        `
      : `
          created_at ${orderDirection},
          id DESC
        `;

  const result = await query<TodoRow>(
    `
      SELECT
        id,
        user_id,
        title,
        description,
        completed,
        status,
        last_status_transition_from,
        last_status_transition_at,
        due_date,
        priority,
        created_at,
        updated_at
      FROM todos
      WHERE ${whereClauses.join(" AND ")}
      ORDER BY ${orderByClause}
    `,
    values,
  );

  return result.rows.map(mapTodoRow);
}

export async function getTodoById(
  todoId: string,
  userId: string,
): Promise<TodoRecord | null> {
  const row = await getTodoRowByIdForUser(todoId, userId);

  return row ? mapTodoRow(row) : null;
}

export async function createTodo(
  userId: string,
  payload: unknown,
): Promise<TodoRecord> {
  const input = normalizeCreateTodoInput(payload);
  const result = await query<TodoRow>(
    `
      INSERT INTO todos (
        id,
        user_id,
        title,
        description,
        completed,
        status,
        due_date,
        priority
      )
      VALUES ($1, $2, $3, $4, $5, $6, $7, $8)
      RETURNING
        id,
        user_id,
        title,
        description,
        completed,
        status,
        last_status_transition_from,
        last_status_transition_at,
        due_date,
        priority,
        created_at,
        updated_at
    `,
    [
      randomUUID(),
      userId,
      input.title,
      input.description,
      getCompletedStateForWorkItemStatus(input.status),
      input.status,
      input.dueDate,
      input.priority,
    ],
  );

  return mapTodoRow(result.rows[0]);
}

export async function updateTodo(
  todoId: string,
  userId: string,
  payload: unknown,
): Promise<TodoRecord> {
  const updates = normalizeUpdateTodoInput(payload);
  const existingTodo = await getTodoRowByIdForUser(todoId, userId);

  if (!existingTodo) {
    throw new TodoNotFoundError("Todo not found.");
  }

  const setClauses: string[] = [];
  const values: unknown[] = [todoId, userId];

  if ("title" in updates) {
    setClauses.push(`title = $${values.length + 1}`);
    values.push(updates.title);
  }

  if ("description" in updates) {
    setClauses.push(`description = $${values.length + 1}`);
    values.push(updates.description);
  }

  if ("dueDate" in updates) {
    setClauses.push(`due_date = $${values.length + 1}`);
    values.push(updates.dueDate);
  }

  if ("priority" in updates) {
    setClauses.push(`priority = $${values.length + 1}`);
    values.push(updates.priority);
  }

  let nextStatus: WorkItemStatus | undefined;

  if ("status" in updates) {
    nextStatus = updates.status;
  } else if ("completed" in updates) {
    const completed = updates.completed;

    if (completed === undefined) {
      throw new TodoValidationError("completed must be a boolean.");
    }

    nextStatus = getWorkItemStatusFromCompletionFlag(
      completed,
      existingTodo.status,
    );
  }

  if (nextStatus !== undefined) {
    if (
      !canTransitionWorkItemStatus(existingTodo.status, nextStatus)
    ) {
      throw new TodoStatusTransitionError(existingTodo.status, nextStatus);
    }

    setClauses.push(`status = $${values.length + 1}`);
    values.push(nextStatus);
    setClauses.push(`completed = $${values.length + 1}`);
    values.push(getCompletedStateForWorkItemStatus(nextStatus));

    if (nextStatus !== existingTodo.status) {
      setClauses.push(`last_status_transition_from = $${values.length + 1}`);
      values.push(existingTodo.status);
      setClauses.push("last_status_transition_at = CURRENT_TIMESTAMP");
    }
  }

  setClauses.push("updated_at = CURRENT_TIMESTAMP");

  const result = await query<TodoRow>(
    `
      UPDATE todos
      SET ${setClauses.join(", ")}
      WHERE id = $1
        AND user_id = $2
      RETURNING
        id,
        user_id,
        title,
        description,
        completed,
        status,
        last_status_transition_from,
        last_status_transition_at,
        due_date,
        priority,
        created_at,
        updated_at
    `,
    values,
  );

  const todo = result.rows[0];

  if (!todo) {
    throw new TodoNotFoundError("Todo not found.");
  }

  return mapTodoRow(todo);
}

export async function deleteTodo(
  todoId: string,
  userId: string,
): Promise<void> {
  const result = await query(
    `
      DELETE FROM todos
      WHERE id = $1
        AND user_id = $2
    `,
    [todoId, userId],
  );

  if (result.rowCount === 0) {
    throw new TodoNotFoundError("Todo not found.");
  }
}

